cd /tmp/sv-5e4bb3c8dd8140aa854b12916ec683f7/advanced-multi-complexity && dotnet package list --format json > after-cpm-packages.json 2>&1; echo "EXIT: $?"; python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

changes = []
unchanged = []
for bp, ap in zip(baseline['projects'], after['projects']):
    proj = bp['path'].split('/')[-1]
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        fw = bf['framework']
        b_pkgs = {p['id']: p['resolvedVersion'] for p in bf['topLevelPackages']}
        a_pkgs = {p['id']: p['resolvedVersion'] for p in af['topLevelPackages']}
        for pid in sorted(set(b_pkgs) | set(a_pkgs)):
            bv = b_pkgs.get(pid, '-')
            av = a_pkgs.get(pid, '-')
            if bv != av:
                changes.append((proj, fw, pid, bv, av))
            else:
                unchanged.append((proj, fw, pid, bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ==='  )
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]}  {u[3]}')
"

